import RecordStoreCore, { WatchableCellValuesInFieldKeyPrefix, WatchableRecordStoreKeysCore } from '../../shared/models/record_store_core';
import { isEnumValue } from '../../shared/private_utils';
import { Record } from './record';
const WatchableRecordStoreKeys = Object.freeze({
  ...WatchableRecordStoreKeysCore,
  recordOrder: 'recordOrder'
});

/**
 * The string case is to accommodate prefix keys
 *
 * @internal
 */

/**
 * One RecordStore exists per table, and contains all the record data associated with that table.
 * Table itself is for schema information only, so isn't the appropriate place for this data.
 *
 * @internal
 */
export class RecordStore extends RecordStoreCore {
  static _className = 'RecordStore';
  static _isWatchableKey(key) {
    return isEnumValue(WatchableRecordStoreKeys, key) || key.startsWith(WatchableCellValuesInFieldKeyPrefix);
  }
  _constructRecord(recordId, parentTable) {
    return new Record(this._sdk, this, parentTable, recordId);
  }

  /**
   * The record Ids in this table.
   */
  get recordIds() {
    return this._data.recordOrder
    // Most of the time, the recordIds in recordOrder should be the same as
    // the recordIds in this._recordModelsById. However, consider the following
    // sequence of events:
    // 1. RecordStore currently has the following recordIds: ['rec1', 'rec2', 'rec3']
    // 2. Call deleteRecordsAsync on rec1
    // 3. Optimistically remove rec1 from recordOrder + recordModelsById, leaving ['rec2', 'rec3']
    // 4. Send update to liveapp to delete rec1
    // 5. While waiting for liveapp to respond, call deleteRecordsAsync on rec2
    // 6. Optimistically remove rec2 from recordOrder + recordModelsById, leaving ['rec3']
    // 7. Send update to liveapp to delete rec2
    // 8. Liveapp responds to the first delete request and sends an update to
    //    set recordOrder to ['rec2', 'rec3']
    // 9. Liveapp receives the second delete request
    //
    // The problem is that after step 8, the recordOrder is ['rec2', 'rec3'], but rec2
    // has already been deleted from the recordStore in step 6.
    // Liveapp can't do anything differently here, because it doesn't receive the delete
    // request for rec2 until step 9.
    .filter(recordId => this.getRecordByIdIfExists(recordId) !== null);
  }
  __onDataDeletion() {
    // nothing to do
  }
  triggerOnChangeForDirtyPaths(dirtyPaths) {
    super.triggerOnChangeForDirtyPaths(dirtyPaths);
    if (dirtyPaths.recordOrder) {
      this._onChange(WatchableRecordStoreKeys.recordOrder);
    }
  }
}